"use client";

import { Upload, Camera, X } from "lucide-react";
import { useCallback, useState, useEffect } from "react";
import { cn } from "@/lib/utils";

interface ImageUploadProps {
  onImageSelect: (base64: string | null) => void;
  selectedImage: string | null;
}

export default function ImageUpload({ onImageSelect, selectedImage }: ImageUploadProps) {
  const [isDragging, setIsDragging] = useState(false);

  const handleFile = useCallback((file: File) => {
    if (file && file.type.startsWith("image/")) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onImageSelect(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  }, [onImageSelect]);

  // Paste Event Listener
  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      if (e.clipboardData && e.clipboardData.items) {
        for (let i = 0; i < e.clipboardData.items.length; i++) {
          const item = e.clipboardData.items[i];
          if (item.type.startsWith("image/")) {
            const file = item.getAsFile();
            if (file) {
                handleFile(file);
                e.preventDefault(); // Prevent default paste behavior
            }
          }
        }
      }
    };

    window.addEventListener("paste", handlePaste);
    return () => {
      window.removeEventListener("paste", handlePaste);
    };
  }, [handleFile]);

  const onDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  }, [handleFile]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      handleFile(e.target.files[0]);
    }
  };

  if (selectedImage) {
    return (
      <div className="relative w-full h-64 md:h-80 bg-gray-100 rounded-xl overflow-hidden group shadow-md border border-gray-200">
        <img 
            src={selectedImage} 
            alt="Uploaded ingredients" 
            className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
            <button
                onClick={() => onImageSelect(null)}
                className="p-3 bg-white/20 backdrop-blur-md rounded-full text-white hover:bg-white/40 transition-colors"
                title="Remove Image"
            >
                <X className="w-8 h-8" />
            </button>
        </div>
      </div>
    );
  }

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={onDrop}
      className={cn(
        "border-3 border-dashed rounded-xl p-8 text-center cursor-pointer transition-colors h-64 md:h-80 flex flex-col items-center justify-center relative",
        isDragging ? "border-orange-500 bg-orange-50" : "border-gray-300 hover:border-orange-400 hover:bg-gray-50"
      )}
    >
      <input
        type="file"
        accept="image/*"
        onChange={handleChange}
        className="hidden"
        id="image-upload"
      />
      <label htmlFor="image-upload" className="flex flex-col items-center cursor-pointer w-full h-full justify-center">
        <div className="p-4 bg-orange-100 rounded-full mb-4 text-orange-600">
            <Camera className="w-8 h-8" />
        </div>
        <p className="text-lg font-medium text-gray-700">点击或拖拽图片到这里</p>
        <p className="text-sm text-gray-500 mt-2">支持 JPG, PNG 格式</p>
        <div className="mt-4 px-3 py-1 bg-gray-100 rounded text-xs text-gray-500 border border-gray-200">
            支持 Ctrl+V / Cmd+V 直接粘贴
        </div>
      </label>
    </div>
  );
}
